  1	import * as React from 'react';
  2	import { WizardNodeState } from '@odf/core/components/create-storage-system/reducer';
  3	import {
  4	  createWizardNodeState,
  5	  getTotalCpu,
  6	  getTotalMemoryInGiB,
  7	} from '@odf/core/components/utils';
  8	import {
  9	  resourceProfileTooltip,
 10	  resourceRequirementsTooltip,
 11	} from '@odf/core/constants';
 12	import { useNodesData } from '@odf/core/hooks';
 13	import { ResourceProfile } from '@odf/core/types';
 14	import {
 15	  getResourceProfileRequirements,
 16	  isResourceProfileAllowed,
 17	  nodesWithoutTaints,
 18	} from '@odf/core/utils';
 19	import { SingleSelectDropdown } from '@odf/shared/dropdown';
 20	import { FieldLevelHelp } from '@odf/shared/generic/FieldLevelHelp';
 21	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 22	import { TFunction } from 'react-i18next';
 23	import {
 24	  Text,
 25	  TextVariants,
 26	  TextContent,
 27	  SelectOption,
 28	} from '@patternfly/react-core';
 29	import './configure-performance.scss';
 30	
 31	const selectOptions = (t: TFunction, forceLean: boolean, osdAmount: number) =>
 32	  Object.entries(ResourceProfile).map((value: [string, ResourceProfile]) => {
 33	    const displayName = t('{{mode}} mode', { mode: value[0] });
 34	    let profile = value[1];
 35	    const { minCpu, minMem } = getResourceProfileRequirements(
 36	      profile,
 37	      osdAmount
 38	    );
 39	    const description = `CPUs required: ${minCpu}, Memory required: ${minMem} GiB`;
 40	    const isDisabled =
 41	      forceLean &&
 42	      [ResourceProfile.Balanced, ResourceProfile.Performance].includes(profile);
 43	    return (
 44	      <SelectOption
 45	        key={profile}
 46	        value={profile}
 47	        description={description}
 48	        data-test-id={`${value[0]} mode`}
 49	        isDisabled={isDisabled}
 50	      >
 51	        {displayName}
 52	      </SelectOption>
 53	    );
 54	  });
 55	
 56	export const PerformanceHeaderText: React.FC = () => {
 57	  const { t } = useCustomTranslation();
 58	  return (
 59	    <Text id="configure-performance" component={TextVariants.h4}>
 60	      <span className="pf-v6-u-mr-sm">{t('Configure performance')}</span>
 61	      <FieldLevelHelp>{resourceProfileTooltip(t)}</FieldLevelHelp>
 62	    </Text>
 63	  );
 64	};
 65	
 66	type ProfileRequirementsTextProps = {
 67	  selectedProfile: ResourceProfile;
 68	  osdAmount: number;
 69	};
 70	
 71	export const ProfileRequirementsText: React.FC<
 72	  ProfileRequirementsTextProps
 73	> = ({ selectedProfile, osdAmount }) => {
 74	  const { t } = useCustomTranslation();
 75	  const { minCpu, minMem } = getResourceProfileRequirements(
 76	    selectedProfile,
 77	    osdAmount
 78	  );
 79	  return (
 80	    <TextContent>
 81	      <Text id="resource-requirements" component={TextVariants.h4}>
 82	        <span className="pf-v6-u-mr-sm">
 83	          {t('Aggregate resource requirements for {{selectedProfile}} mode', {
 84	            selectedProfile,
 85	          })}
 86	        </span>
 87	        {selectedProfile === ResourceProfile.Performance && (
 88	          <FieldLevelHelp>{resourceRequirementsTooltip(t)}</FieldLevelHelp>
 89	        )}
 90	      </Text>
 91	      <Text id="cpu-requirements-desc" className="pf-v6-u-font-size-sm">
 92	        <div className="pf-v6-u-mb-sm">
 93	          <span className="pf-v5-u-disabled-color-100">
 94	            {t('CPUs required')}:
 95	          </span>{' '}
 96	          <span className="pf-v6-u-font-size-md">
 97	            {minCpu} {t('CPUs')}
 98	          </span>
 99	        </div>
100	        <div>
101	          <span className="pf-v5-u-disabled-color-100">
102	            {t('Memory required')}:
103	          </span>{' '}
104	          <span className="pf-v6-u-font-size-md">
105	            {minMem} {t('GiB')}
106	          </span>
107	        </div>
108	      </Text>
109	    </TextContent>
110	  );
111	};
112	
113	type ConfigurePerformanceProps = {
114	  onResourceProfileChange: (newProfile: ResourceProfile) => void;
115	  resourceProfile: ResourceProfile;
116	  headerText?: React.FC;
117	  profileRequirementsText?: React.FC<ProfileRequirementsTextProps>;
118	  selectedNodes: WizardNodeState[];
119	  osdAmount?: number;
120	};
121	
122	const ConfigurePerformance: React.FC<ConfigurePerformanceProps> = ({
123	  onResourceProfileChange,
124	  resourceProfile,
125	  headerText: HeaderTextComponent,
126	  profileRequirementsText: ProfileRequirementsTextComponent,
127	  selectedNodes,
128	  osdAmount,
129	}) => {
130	  const { t } = useCustomTranslation();
131	  const [availableNodes, availableNodesLoaded, availableNodesLoadError] =
132	    useNodesData();
133	
134	  // Force Lean mode when all selectable capacity is not enough for higher profiles.
135	  let forceLean = false;
136	  if (availableNodesLoaded && !availableNodesLoadError) {
137	    const selectableNodes = createWizardNodeState(
138	      nodesWithoutTaints(availableNodes)
139	    );
140	    const allCpu = getTotalCpu(selectableNodes);
141	    const allMem = getTotalMemoryInGiB(selectableNodes);
142	    if (
143	      !isResourceProfileAllowed(
144	        ResourceProfile.Balanced,
145	        allCpu,
146	        allMem,
147	        osdAmount
148	      )
149	    ) {
150	      forceLean = true;
151	    }
152	  }
153	  if (forceLean === true && resourceProfile !== ResourceProfile.Lean) {
154	    onResourceProfileChange(ResourceProfile.Lean);
155	  }
156	
157	  // Set error icon in dropdown when appropriate.
158	  const isProfileAllowed = resourceProfile
159	    ? isResourceProfileAllowed(
160	        resourceProfile,
161	        getTotalCpu(selectedNodes),
162	        getTotalMemoryInGiB(selectedNodes),
163	        osdAmount
164	      )
165	    : true;
166	  const validated =
167	    selectedNodes.length === 0 || isProfileAllowed ? 'default' : 'error';
168	
169	  return (
170	    <div className="pf-v6-u-mb-lg">
171	      <TextContent className="pf-v6-u-mb-md">
172	        {HeaderTextComponent && <HeaderTextComponent />}
173	        <Text
174	          id="configure-performance-desc"
175	          className="pf-v6-u-font-size-sm pf-v5-u-disabled-color-100"
176	        >
177	          {t(
178	            'Select a profile to customise the performance of the Data Foundation cluster to meet your requirements.'
179	          )}
180	        </Text>
181	      </TextContent>
182	      <SingleSelectDropdown
183	        aria-label={t('Select a performance mode from the list')}
184	        selectedKey={resourceProfile}
185	        id="resource-profile"
186	        className="odf-configure-performance__selector pf-v6-u-mb-md"
187	        selectOptions={selectOptions(t, forceLean, osdAmount)}
188	        onChange={onResourceProfileChange}
189	        validated={validated}
190	      />
191	      {resourceProfile && ProfileRequirementsTextComponent && (
192	        <ProfileRequirementsTextComponent
193	          selectedProfile={resourceProfile}
194	          osdAmount={osdAmount}
195	        />
196	      )}
197	    </div>
198	  );
199	};
200	
201	export default ConfigurePerformance;

