  1	import * as React from 'react';
  2	import { createWizardNodeState } from '@odf/core/components/utils';
  3	import { useNodesData } from '@odf/core/hooks';
  4	import { ResourceProfile } from '@odf/core/types';
  5	import { render, screen } from '@testing-library/react';
  6	import { userEvent } from '@testing-library/user-event';
  7	import { createFakeNodesData } from '../../../../../../jest/helpers';
  8	import ConfigurePerformance, {
  9	  ProfileRequirementsText,
 10	} from './configure-performance';
 11	
 12	jest.mock('@odf/core/hooks', () => ({
 13	  useNodesData: jest.fn(),
 14	}));
 15	
 16	const onResourceProfileChange = jest.fn();
 17	
 18	const errorIconSelector = '.pf-v6-c-menu-toggle__status-icon';
 19	
 20	describe('Configure Performance', () => {
 21	  beforeEach(() => {
 22	    onResourceProfileChange.mockClear();
 23	  });
 24	
 25	  it('renders default profile and selects Performance profile', async () => {
 26	    const cpu = 12;
 27	    const memory = 32 * 1000 * 1000 * 1000;
 28	    const nodes = createFakeNodesData(3, cpu, memory);
 29	    const selectedNodes = createWizardNodeState(nodes);
 30	    (useNodesData as jest.Mock).mockReturnValueOnce([nodes, true, null]);
 31	
 32	    const user = userEvent.setup();
 33	    const { container } = render(
 34	      <ConfigurePerformance
 35	        onResourceProfileChange={onResourceProfileChange}
 36	        resourceProfile={ResourceProfile.Balanced}
 37	        selectedNodes={selectedNodes}
 38	      />
 39	    );
 40	
 41	    const dropdown = screen.getByRole('combobox', {
 42	      name: /select a performance mode from the list/i,
 43	    });
 44	    expect(dropdown).toHaveTextContent('{{mode}} mode');
 45	
 46	    const errorIcon = container.querySelector(errorIconSelector);
 47	    expect(errorIcon).toBeFalsy();
 48	
 49	    await user.click(dropdown);
 50	    const performanceOption = screen.getByTestId('Performance mode');
 51	    await user.click(performanceOption);
 52	    expect(onResourceProfileChange).toHaveBeenNthCalledWith(
 53	      1,
 54	      ResourceProfile.Performance
 55	    );
 56	  });
 57	
 58	  it('forces Lean when selectable nodes do not allow higher profiles', () => {
 59	    (useNodesData as jest.Mock).mockReturnValueOnce([[], true, null]);
 60	
 61	    render(
 62	      <ConfigurePerformance
 63	        onResourceProfileChange={onResourceProfileChange}
 64	        resourceProfile={ResourceProfile.Balanced}
 65	        selectedNodes={[]}
 66	      />
 67	    );
 68	    expect(onResourceProfileChange).toHaveBeenNthCalledWith(
 69	      1,
 70	      ResourceProfile.Lean
 71	    );
 72	  });
 73	
 74	  it('shows error icon in the dropdown when resource requirements are not enough', () => {
 75	    const cpu = 12;
 76	    const memory = 32 * 1000 * 1000 * 1000;
 77	    const nodes = createFakeNodesData(3, cpu, memory);
 78	    const selectedNodes = createWizardNodeState(nodes);
 79	    (useNodesData as jest.Mock).mockReturnValueOnce([nodes, true, null]);
 80	
 81	    const { container } = render(
 82	      <ConfigurePerformance
 83	        onResourceProfileChange={onResourceProfileChange}
 84	        resourceProfile={ResourceProfile.Performance}
 85	        selectedNodes={selectedNodes}
 86	      />
 87	    );
 88	    const dropdown = screen.getByRole('button', {
 89	      name: /select a performance mode from the list/i,
 90	    });
 91	    expect(dropdown).toHaveTextContent('{{mode}} mode');
 92	
 93	    const errorIcon = container.querySelector(errorIconSelector);
 94	    expect(errorIcon).toBeVisible();
 95	    expect(onResourceProfileChange).toHaveBeenCalledTimes(0);
 96	  });
 97	
 98	  it('shows higher resource requirements due to high amount of OSDs', () => {
 99	    const cpu = 12;
100	    const memory = 32 * 1000 * 1000 * 1000;
101	    const nodes = createFakeNodesData(3, cpu, memory);
102	    const selectedNodes = createWizardNodeState(nodes);
103	    (useNodesData as jest.Mock).mockReturnValueOnce([nodes, true, null]);
104	
105	    render(
106	      <ConfigurePerformance
107	        onResourceProfileChange={onResourceProfileChange}
108	        resourceProfile={ResourceProfile.Balanced}
109	        selectedNodes={selectedNodes}
110	        osdAmount={9}
111	        profileRequirementsText={ProfileRequirementsText}
112	      />
113	    );
114	
115	    const dropdown = screen.getByRole('button', {
116	      name: /select a performance mode from the list/i,
117	    });
118	    expect(dropdown).toHaveTextContent('{{mode}} mode');
119	    expect(screen.getByText(/42 CPUs/i)).toBeInTheDocument();
120	    expect(screen.getByText(/102 GiB/i)).toBeInTheDocument();
121	  });
122	});

