112	type ConfigurePerformanceProps = {
113	  onResourceProfileChange: (newProfile: ResourceProfile) => void;
114	  resourceProfile: ResourceProfile;
115	  headerText?: React.FC;
116	  profileRequirementsText?: React.FC<ProfileRequirementsTextProps>;
117	  selectedNodes: WizardNodeState[];
118	  osdAmount?: number;
119	};
120	
121	const ConfigurePerformance: React.FC<ConfigurePerformanceProps> = ({
122	  onResourceProfileChange,
123	  resourceProfile,
124	  headerText: HeaderTextComponent,
125	  profileRequirementsText: ProfileRequirementsTextComponent,
126	  selectedNodes,
127	  osdAmount,
128	}) => {
129	  const { t } = useCustomTranslation();
130	  const [availableNodes, availableNodesLoaded, availableNodesLoadError] =
131	    useNodesData();
132	
133	  // Force Lean mode when all selectable capacity is not enough for higher profiles.
134	  let forceLean = false;
135	  if (availableNodesLoaded && !availableNodesLoadError) {
136	    const selectableNodes = createWizardNodeState(
137	      nodesWithoutTaints(availableNodes)
138	    );
139	    const allCpu = getTotalCpu(selectableNodes);
140	    const allMem = getTotalMemoryInGiB(selectableNodes);
141	    if (
142	      !isResourceProfileAllowed(
143	        ResourceProfile.Balanced,
144	        allCpu,
145	        allMem,
146	        osdAmount
147	      )
148	    ) {
149	      forceLean = true;
150	    }
151	  }
152	  if (forceLean === true && resourceProfile !== ResourceProfile.Lean) {
153	    onResourceProfileChange(ResourceProfile.Lean);
154	  }
155	
156	  // Set error icon in dropdown when appropriate.
157	  const isProfileAllowed = resourceProfile
158	    ? isResourceProfileAllowed(
159	        resourceProfile,
160	        getTotalCpu(selectedNodes),
161	        getTotalMemoryInGiB(selectedNodes),
162	        osdAmount
163	      )
164	    : true;
165	  const validated =
166	    selectedNodes.length === 0 || isProfileAllowed ? 'default' : 'error';
167	
168	  return (
169	    <div className="pf-v6-u-mb-lg">
170	      <Content className="pf-v6-u-mb-md">
171	        {HeaderTextComponent && <HeaderTextComponent />}
172	        <Content
173	          id="configure-performance-desc"
174	          className="pf-v6-u-font-size-sm"
175	          style={{ color: 'var(--pf-t--global--text--color--disabled)' }}
176	        >
177	          {t(
178	            'Select a profile to customise the performance of the Data Foundation cluster to meet your requirements.'
179	          )}
180	        </Content>
181	      </Content>
182	      <SingleSelectDropdown
183	        aria-label={t('Select a performance mode from the list')}
184	        selectedKey={resourceProfile}
185	        id="resource-profile"
186	        className="odf-configure-performance__selector pf-v6-u-mb-md"
187	        selectOptions={selectOptions(t, forceLean, osdAmount)}
188	        onChange={onResourceProfileChange}
189	        validated={validated}
190	      />
191	      {resourceProfile && ProfileRequirementsTextComponent && (
192	        <ProfileRequirementsTextComponent
193	          selectedProfile={resourceProfile}
194	          osdAmount={osdAmount}
195	        />
196	      )}
197	    </div>
198	  );
199	};
